def isAnagram(s: str, t: str) -> bool:
    s1 = []
    t1 = []
    for i in t:
        t1.append(i)

    for i in s:
        s1.append(i)

    s_len = len(s)
    counter=0

    while len(t1) > 0:
        if t1[0] in s and t1.count(t1[0]) == s1.count(t1[0]):
            index = s1.index(t1[0])
            t1.remove(t1[0]) 
            s1.remove(s1[index])
            counter += 1
        else:
            return False

    if counter == s_len and len(t1) == 0:
        return True
    else:
        return False

def isAnagram(s, t):
    return sorted(s) == sorted(t)


